{"file_text": "@namespace sv_40a66bd6f231467fae25e8bd217e67d8.Components.Pages.Settings
@using sv_40a66bd6f231467fae25e8bd217e67d8.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4>Appearance</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <!-- Theme -->
        <div class="mb-4">
            <h6>Theme</h6>
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme}")"
                           value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                </div>
            }
        </div>

        <!-- Font Size -->
        <div class="mb-4">
            <h6>Font Size</h6>
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size}")"
                           value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                </div>
            }
        </div>

        <!-- Language -->
        <div class="mb-4">
            <h6>Language</h6>
            <select class="form-select" style="max-width: 250px;" @bind="_language">
                <option value="en">English</option>
                <option value="es">Español</option>
                <option value="fr">Français</option>
                <option value="de">Deutsch</option>
                <option value="ja">日本語</option>
                <option value="zh">中文</option>
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="mb-4">
            <h6>Preview</h6>
            <div class="preview-box @PreviewThemeClass" style="font-size: @PreviewFontSize; padding: @PreviewPadding;">
                <p class="mb-1"><strong>Sample Heading</strong></p>
                <p class="mb-1">This is how your content will look with the selected settings.</p>
                <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
        }
        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
        }
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewPadding => _compactMode ? "0.5rem" : "1rem";

    private string PreviewButtonClass => _theme == "Dark" ? "btn-light" : "btn-primary";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;

        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _successMessage = "Appearance settings saved!";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}
