arguments.file_text:
@page "/settings"
@namespace sv_40a66bd6f231467fae25e8bd217e67d8.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 120px);
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
}

.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    overflow-y: auto;
}

::deep .section-panel h4 {
    margin-bottom: 1.25rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

